SELECT *, LAG(on_time_pct) OVER (PARTITION BY reporting_airline ORDER BY year, month) AS prev_month_otp, ROUND(on_time_pct - LAG(on_time_pct) OVER (PARTITION BY reporting_airline ORDER BY year, month), 2) AS mom_otp_change, ROUND(cancellation_rate - LAG(cancellation_rate) OVER (PARTITION BY reporting_airline ORDER BY year, month), 2) AS mom_cancel_rate_change, ROUND(avg_arr_delay_min - LAG(avg_arr_delay_min) OVER (PARTITION BY reporting_airline ORDER BY year, month), 2) AS mom_arr_delay_change, ROUND(100.0 * (total_flights - LAG(total_flights) OVER (PARTITION BY reporting_airline ORDER BY year, month)) / NULLIF(LAG(total_flights) OVER (PARTITION BY reporting_airline ORDER BY year, month), 0), 2) AS mom_volume_change_pct, LAG(on_time_pct, 12) OVER (PARTITION BY reporting_airline ORDER BY year, month) AS yoy_otp, ROUND(on_time_pct - LAG(on_time_pct, 12) OVER (PARTITION BY reporting_airline ORDER BY year, month), 2) AS yoy_otp_change, RANK() OVER (PARTITION BY year, month ORDER BY on_time_pct DESC) AS otp_rank, RANK() OVER (PARTITION BY year, month ORDER BY cancellation_rate ASC) AS cancellation_rank, RANK() OVER (PARTITION BY year, month ORDER BY total_flights DESC) AS volume_rank, CASE WHEN on_time_pct - LAG(on_time_pct) OVER (PARTITION BY reporting_airline ORDER BY year, month) > 1 THEN 'Improving' WHEN on_time_pct - LAG(on_time_pct) OVER (PARTITION BY reporting_airline ORDER BY year, month) < -1 THEN 'Declining' ELSE 'Stable' END AS otp_trend_direction FROM all_airline_kpi
